/// <summary>
///
/// </summary>
/// <param name="sender"></param>
/// <param name="e"></param>
[FormControlEventHandler(formControlStr(LogisticsAddressSetup, RuralMuncipality_StateFilter), FormControlEventType::Lookup)]
public static void RuralMuncipality_StateFilter_OnLookup(FormControl sender, FormControlEventArgs e)
{
    FormRun formRun = sender.formRun();
    FormStringControl CountryRegionId_RUControl = formRun.design().controlName(formControlStr(LogisticsAddressSetup, RuralMuncipality_CountryRegionFilter)) as FormStringControl;
    LogisticsAddressState::lookupStateId(sender, CountryRegionId_RUControl.text());
}

/// <summary>
///
/// </summary>
/// <param name="sender"></param>
/// <param name="e"></param>
[FormControlEventHandler(formControlStr(LogisticsAddressSetup, RuralMuncipality_CountyFilter), FormControlEventType::Lookup)]
public static void RuralMuncipality_CountyFilter_OnLookup(FormControl sender, FormControlEventArgs e)
{
    FormRun formRun = sender.formRun();
    FormStringControl CountryRegionId_RUControl = formRun.design().controlName(formControlStr(LogisticsAddressSetup, RuralMuncipality_CountryRegionFilter)) as FormStringControl;
    FormStringControl StateId_RUControl = formRun.design().controlName(formControlStr(LogisticsAddressSetup, RuralMuncipality_CountryRegionFilter)) as FormStringControl;
    LogisticsAddressCounty::lookupCountyId(sender, CountryRegionId_RUControl.text(),StateId_RUControl.text());
}

/// <summary>
///
/// </summary>
/// <param name="sender"></param>
/// <param name="e"></param>
[FormControlEventHandler(formControlStr(LogisticsAddressSetup, ETGRuralMuncipality_City), FormControlEventType::Lookup)]
public static void ETGRuralMuncipality_City_OnLookup(FormControl sender, FormControlEventArgs e)
{
    FormRun formRun = sender.formRun();

    FormStringControl CountryRegionId_RUControl = formRun.design().controlName(formControlStr(LogisticsAddressSetup, ETGRuralMuncipality_CountryRegionId_RU)) as FormStringControl;
    FormStringControl StateId_RUControl = formRun.design().controlName(formControlStr(LogisticsAddressSetup, ETGRuralMuncipality_StateId_RU)) as FormStringControl;
    FormStringControl County_RUControl = formRun.design().controlName(formControlStr(LogisticsAddressSetup, ETGRuralMuncipality_CountyId_RU)) as FormStringControl;

    LogisticsAddressCity::lookupCityId_RU(sender, CountryRegionId_RUControl.text(),
                                            StateId_RUControl.text(),
                                            County_RUControl.text());
}
